#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *arr = (int*)malloc(N * sizeof(int));
        int freq[101] = {0};
        for (int i = 0; i < N; ++i) {
            scanf("%d", &arr[i]);
            ++freq[arr[i]];
        }
        for (int i = 0; i < N; ++i) {
            printf("%d", freq[arr[i]]);
            if (i + 1 < N) printf(" ");
        }
        printf("
");
        free(arr);
    }
    return 0;
}

